let level = msg.payload.level;
if (level === undefined) return null;

// Convert to percent for text widget
let percent = Math.round((level / 200) * 100);
let textMsg = { payload: percent + "%" };

// Send scaled value to your dashboard slider (if you have one)
let sliderMsg = { payload: percent };

// Send to Victron Virtual Device (Basic slider) via Switch control node
// (Adjust output_1 if your virtual switch is output_2, etc.)
let vdMsg = {
  payload: {
    "/SwitchableOutput/output_1/Dimming": percent
  }
};

return [sliderMsg, vdMsg];

let frame = msg.payload;
let dgn = (frame.canid >> 8) & 0x3FFFF;

// Only care about DIMMER_COMMAND_2 (0x1FEDB)
if (dgn !== 0x1FEDA) return null;

// Get the group/subflow variable
let inst = env.get("INSTANCE");   // comes from subflow/group environment config

let instance = frame.data[0];
if (instance !== inst) return null;  // filter by group variable

let level = frame.data[2];
msg.payload = { level };
return msg;

// Input: msg.payload = 0–100 (percent brightness)
// Output: msg.payload = full command object with fadeRate scaled 0–251

let percent = Number(msg.payload);

// Clamp to valid range
if (percent < 0) percent = 0;
if (percent > 100) percent = 100;

// Scale percent (0–100) to desiredLevel (0–200)
let desiredLevel = Math.round((percent / 100) * 200);

msg.payload = {
    command: "DIMMER_COMMAND_2",
    desiredLevel: desiredLevel
};

return msg;

// Input: msg.payload = { desiredLevel }
// Output: msg.payload = { canid, data, ext, rtr, dlc }

let inst = env.get("INSTANCE");   // gets the group variable

function buildFrame(dgn, data) {
    return {
        canid: (dgn << 8) | 0x01,   // Example source address = 1; adjust if needed
        ext: true,
        rtr: false,
        dlc: data.length,
        data: data
    };
}

let p = msg.payload;

// Always DIMMER_COMMAND_2, DGN = 0x1FEDB, instance fixed at 35
let out = buildFrame(0x1FEDB, [
    inst,                  // instance from variable
    p.group || 0,        // group, if provided
    p.desiredLevel || 0  // brightness level
]);

msg.payload = out;
return msg;

let level = msg.payload.level;

// Default OFF state
let state = false;   

// Switch ON if level > 0
if (level > 0) state = true;

// Build update message for ui-switch
msg = {
    payload: state,   // true/false drives the switch toggle
};

return msg;

