// Node-RED Function with two outputs:
// Output 1 -> SOC (%)
// Output 2 -> Time Remaining (formatted string)

let frame = msg.payload;

// Extract PGN and Source Address from 29-bit CANID
let dgn = (frame.canid >> 8) & 0x3FFFF;   // PGN (18 bits)
let sa  = frame.canid & 0xFF;             // Source Address (8 bits)

// Only accept from Lithionics BMS (0x46 = 70 decimal)
if (sa !== 0x46) return [null, null];

// ---- DC_SOURCE_STATUS_2 (0x1FFFC) ----
if (dgn === 0x1FFFC) {
    // SOC at Byte 4
    let rawSOC = frame.data[4];
    let soc = rawSOC * 0.5;  // 0.5% per bit

    // Time Remaining at Bytes 5-6 (little endian)
    let rawTime = frame.data[5] | (frame.data[6] << 8);
    let minutes = rawTime;

    let days = Math.floor(minutes / (24 * 60));
    let hours = Math.floor((minutes % (24 * 60)) / 60);
    let mins = minutes % 60;

    let timeString = `${days} days, ${hours} hrs, ${mins} min`;

    return [
        { payload: soc }, 
        { payload: timeString }
    ];
}

// Ignore all other frames
return [null, null];

// Store selected time into flow context
let timeString = msg.payload; // e.g. "14:30"

// Force to string
if (timeString === undefined || timeString === null) {
    timeString = "";
} else {
    timeString = String(timeString);
}

flow.set("scheduledTime", timeString);

// Status indicator
node.status({
    fill: "green",
    shape: "dot",
    text: "Scheduled: " + timeString
});

// Output message with current scheduled time
return {
    topic: "ScheduledTime",
    payload: timeString
};

// Get scheduled time
let scheduled = flow.get("scheduledTime");
if (!scheduled) return null;

// Current time (HH:MM)
let now = new Date();
let current = now.getHours().toString().padStart(2,"0") + ":" +
              now.getMinutes().toString().padStart(2,"0");

// Compare
if (current === scheduled) {
    // Build your payload here
    msg.payload = {
    "command": "DIMMER_COMMAND_2",
    "desiredLevel": 0
}
    return msg;
}

return null;

// Reads switch states from flow context (set by ui_switch nodes)
// Adds master switch (default false) to disable all outputs
// Passes inject msg to outputs depending on switch logic
// Shows status with active outputs

let master = flow.get("masterSwitch");
if (master === undefined) master = false;  // default to false

let s1 = flow.get("switch1");
let s2 = flow.get("switch2");
let s3 = flow.get("switch3");
let s4 = flow.get("switch4");
let s5 = flow.get("switch5");
let s6 = flow.get("switch6");

let out = [null, null, null, null, null, null];

// If master switch is OFF, block all outputs
if (master === false) {
    node.status({ fill: "red", shape: "ring", text: "Master OFF" });
    return out;
}

// Otherwise, allow per-switch logic
if (s1 !== false) out[0] = RED.util.cloneMessage(msg);
if (s2 !== false) out[1] = RED.util.cloneMessage(msg);
if (s3 !== false) out[2] = RED.util.cloneMessage(msg);
if (s4 !== false) out[3] = RED.util.cloneMessage(msg);
if (s5 !== false) out[4] = RED.util.cloneMessage(msg);
if (s6 !== false) out[5] = RED.util.cloneMessage(msg);

// Build status text
let active = [];
if (s1 !== false) active.push("1");
if (s2 !== false) active.push("2");
if (s3 !== false) active.push("3");
if (s4 !== false) active.push("4");
if (s5 !== false) active.push("5");
if (s6 !== false) active.push("6");

if (active.length > 0) {
    node.status({ fill: "green", shape: "dot", text: "Active: " + active.join(", ") });
} else {
    node.status({ fill: "yellow", shape: "ring", text: "All OFF (Master ON)" });
}

return out;

// Get scheduled time
let scheduled = flow.get("scheduledTime");
if (!scheduled) return null;

// Current time (HH:MM)
let now = new Date();
let current = now.getHours().toString().padStart(2,"0") + ":" +
              now.getMinutes().toString().padStart(2,"0");

// Compare
if (current === scheduled) {
    // Build your payload here
    msg.payload = {
    "command": "DIMMER_COMMAND_2",
    "desiredLevel": 0
}
    return msg;
}

return null;

// Get scheduled time
let scheduled = flow.get("scheduledTime");
if (!scheduled) return null;

// Current time (HH:MM)
let now = new Date();
let current = now.getHours().toString().padStart(2,"0") + ":" +
              now.getMinutes().toString().padStart(2,"0");

// Compare
if (current === scheduled) {
