  if (SWITCH_MSG_SHAPE === "value") {
    node.send([ null, { topic: SWITCH_TOPIC, payload: { value: valueToken } } ]);
  } else {
    node.send([ null, { topic: SWITCH_TOPIC, payload: valueToken } ]);
  }
}

function blankGroup() {
  if (SWITCH_MSG_SHAPE === "value") {
    node.send([ null, { topic: SWITCH_TOPIC, payload: { value: null } } ]);
