const TIMER_MIN = 60;   // minutes — change as needed

// Code mapping
const ON_CODE  = 3;
const OFF_CODE = 1;

// ---- helpers ----
function sendState(code, state, note) {
  const msg1 = { payload: code };
  const msg2 = { payload: state };

  node.send([msg1, msg2]);

  let fill = "grey";
  if (state === "on") fill = "green";
  else if (state === "timer") fill = "yellow";

  node.status({
    fill,
    shape: "dot",
    text: note || state
  });
}

function cancelTimer() {
  const t = context.get("timerHandle");
  if (t) clearTimeout(t);
  context.set("timerHandle", null);
  context.set("timerEndsAt", null);
}

function startTimer(minutes) {
  cancelTimer();
  const ms = Math.max(1, minutes) * 60 * 1000;
  context.set("timerEndsAt", Date.now() + ms);

  const handle = setTimeout(() => {
    // Timer expired: go to OFF
    sendState(OFF_CODE, "off", "Timer expired → off");
    cancelTimer();
  }, ms);

  context.set("timerHandle", handle);
}

// Normalize incoming payload to "on" | "off" | "timer"
function getAction(val) {
  if (val && typeof val === "object" && "value" in val) val = val.value;

  if (typeof val === "boolean") return val ? "on" : "off";

  if (typeof val === "number") {
    if (val === 3) return "on";
    if (val === 1) return "off";
    return null;
  }

  const s = String(val ?? "").trim().toLowerCase();
  if (s === "3" || s === "on")  return "on";
  if (s === "1" || s === "off") return "off";
  if (s === "timer")            return "timer";
  return null;
}

// ---- main ----
const act = getAction(msg.payload);
if (!act) return null;

if (act === "on") {
  cancelTimer();
  sendState(ON_CODE, "on", "ON → 3");
  return null;
}

if (act === "off") {
  cancelTimer();
  sendState(OFF_CODE, "off", "OFF → 1");
  return null;
}

if (act === "timer") {
  // Output 1: 3, Output 2: "timer"
  sendState(ON_CODE, "timer", "Timer started → 3");
  startTimer(TIMER_MIN);
  return null;
}

return null;

// Combine PV Power and Yield Today into one string for a Text widget.
// Topics expected:
const TOPIC_PV    = "SmartSolar Charger MPPT 150/35 - PV Power (W)";
const TOPIC_YIELD = "SmartSolar Charger MPPT 150/35 - Yield today (kWh)";

// Two NBSPs + "|" + two NBSPs (renders reliably)
const SEP = "\u00A0\u00A0|\u00A0\u00A0";

function toNumber(v) {
  const n = Number(String(v).replace(/[^0-9.\-]/g, ""));
  return Number.isFinite(n) ? n : null;
}

// Persist last-known values
let state = flow.get("solarState") || { pvW: null, yieldWText: null };

// Update arriving value
if (msg.topic === TOPIC_PV) {
  state.pvW = toNumber(msg.payload);                 // watts (number)
} else if (msg.topic === TOPIC_YIELD) {
  const kWh = toNumber(msg.payload);                 // energy today in kWh
  if (kWh !== null) {
    const w = Math.round(kWh * 1000);                // per request: kWh * 1000 and append "W"
    state.yieldWText = `${w}Wh`;                      // (use "Wh" if you meant watt-hours)
  } else {
    state.yieldWText = null;
  }
} else {
  return null; // ignore other topics
}
flow.set("solarState", state);

// Build output STRING: "<pv>W  |  Yield: <yield>"
const pvTxt    = (state.pvW === null)       ? "—" : String(Math.round(state.pvW));
const yieldTxt = (state.yieldWText == null) ? "—" : state.yieldWText;

const out = `${pvTxt}W${SEP}Yield: ${yieldTxt}`;
node.status({ fill: "blue", shape: "dot", text: out });

msg.payload = out;  // guaranteed string
return msg;

// Build a single text string from two sources for a Text widget.
// Topics expected:
const TOPIC_PWR = "Lithionics Battery v9.0.05 - Battery power (W)";
const TOPIC_VLT = "Lithionics Battery v9.0.05 - Battery voltage (V)";

// Two NBSPs + "|" + two NBSPs
const SEP = "\u00A0\u00A0|\u00A0\u00A0";

function toNumber(v) {
  const n = Number(String(v).replace(/[^0-9.\-]/g, ""));
  return Number.isFinite(n) ? n : null;
}
function roundDp(n, dp) {
  const m = Math.pow(10, dp);
  return Math.round(n * m) / m;
}

let state = flow.get("lith_batt_state") || { powerW: null, voltV: null };

if (msg.topic === TOPIC_PWR) {
  state.powerW = toNumber(msg.payload);
} else if (msg.topic === TOPIC_VLT) {
  state.voltV = toNumber(msg.payload);
} else {
  return null;
}
flow.set("lith_batt_state", state);

const powerTxt = (state.powerW == null) ? "—" : String(Math.round(state.powerW));
const voltTxt  = (state.voltV  == null) ? "—" : String(roundDp(state.voltV, 2));

const out = `${powerTxt}W${SEP}${voltTxt}V`;
node.status({ fill: "blue", shape: "dot", text: out });

msg.payload = out; // string
return msg;

// Combine Venus DC System and AC power into one string for a Text widget.
