const TOPIC_DC  = "Venus system - DC System (W)";
const TOPIC_AC1 = "Venus system - AC Consumption L1 (W)";

// Two NBSPs + "|" + two NBSPs (prevents collapsing in some widgets)
const SEP = "\u00A0\u00A0|\u00A0\u00A0";

function toNumber(v) {
  const n = Number(String(v).replace(/[^0-9.\-]/g, ""));
  return Number.isFinite(n) ? n : null;
}

// Persist last-known values
let state = flow.get("venus_power_state") || { dcW: null, ac1W: null };

// Update whichever value arrived
if (msg.topic === TOPIC_DC) {
  state.dcW = toNumber(msg.payload);         // watts (number)
} else if (msg.topic === TOPIC_AC1) {
  state.ac1W = toNumber(msg.payload);        // watts (number)
} else {
  return null; // ignore unrelated topics
}
flow.set("venus_power_state", state);

// Build output STRING with placeholders if missing
const dcTxt  = (state.dcW  == null) ? "—" : String(Math.round(state.dcW));
const acTxt  = (state.ac1W == null) ? "—" : String(Math.round(state.ac1W));

const out = `DC: ${dcTxt}W${SEP}AC: ${acTxt}W`;

node.status({ fill: "blue", shape: "dot", text: out });
msg.payload = out;  // guaranteed string
return msg;

let frame = msg.payload;

// RV-C DGN is CAN ID bits 8..25
let dgn = (frame.canid >> 8) & 0x3FFFF;

// Thermostat ambient temperature status
if (dgn !== 0x1FF9C) return null;

// Optional: filter by INSTANCE variable (zone)
let instFilter = env.get("INSTANCE");
let instance = frame.data[0];
if (instFilter !== undefined && instFilter !== null && instance !== instFilter) return null;

// Ambient temp is bytes 1..2, little-endian uint16
let raw = frame.data[1] | (frame.data[2] << 8);

// RV-C °C scaling: 0.03125°C per count, offset −273°C
let tempC = (raw * 0.03125) - 273;
let tempF = (tempC * 9/5) + 31.6;

// Round to whole °F
let roundedF = Math.round(tempF);

// ---- throttle: only send on change ----
let last = context.get("lastTempF");

if (last === roundedF) {
  return null;   // no change → suppress
}

context.set("lastTempF", roundedF);

// Output only the number
msg.payload = roundedF;
return msg;

let frame = msg.payload;
if (!frame || frame.canid === undefined || !frame.data) return null;

// Extract RV-C DGN
let dgn = (frame.canid >> 8) & 0x3FFFF;

// Thermostat STATUS DGN only
if (dgn !== 0x1FFE2) return null;

// Optional instance filter
let instFilter = env.get("INSTANCE");
let instance = frame.data[0];

if (instFilter !== undefined && instFilter !== null && instance !== instFilter)
    return null;

// Byte 1 → operatingMode is bits 0–3
let b1 = frame.data[1];
let operatingMode = b1 & 0x0F;

// Output boolean only
if (operatingMode === 1) msg.payload = true;
else if (operatingMode === 0) msg.payload = false;
else return null;   // ignore other modes

return msg;

// RV-C Thermostat Operating Mode Setter
// DGN: 0x1FEF9
// Input: true / false
//   false -> Off (0)
//   true  -> Cool (1)
//
// Only modifies:
//   Byte1 bits 0–3 = Operating Mode
// All other bytes = 0xFF (no-change)

const DGN        = 0x1FEF9;
const INSTANCE   = 0;    // thermostat instance
const DEST_ADDR  = 0x01;

function buildFrame(dgn, da, data) {
  return {
    canid: (dgn << 8) | (da & 0xFF),
    ext: true,
    rtr: false,
    dlc: data.length,
    data
  };
}

// Normalize input → boolean
function toBool(v) {
  if (v && typeof v === "object" && "value" in v) v = v.value;

  if (typeof v === "boolean") return v;

  if (typeof v === "number") return v !== 0;

  if (typeof v === "string") {
    const s = v.trim().toLowerCase();
    if (s === "true" || s === "on" || s === "1") return true;
    if (s === "false"|| s === "off"|| s === "0") return false;
  }

  return false;
}

const wantCool = toBool(msg.payload);

// Operating mode nibble only
const operatingMode = wantCool ? 1 : 0;

// Byte1: bits 0–3 used, rest untouched → set to 1s
// RV-C convention: 0xF0 means upper bits "no change"
const byte1 = (operatingMode & 0x0F) | 0xF0;

// Other bytes = no-change
const data = [
  INSTANCE & 0xFF, // byte 0
  byte1,           // byte 1 (operating mode only)
  0xFF,            // fan speed unchanged
  0xFF, 0xFF,      // heat setpoint unchanged
  0xFF, 0xFF       // cool setpoint unchanged
];

const frame = buildFrame(DGN, DEST_ADDR, data);

return { payload: frame };

let frame = msg.payload;
if (!frame || frame.canid === undefined || !frame.data) return null;

// Extract RV-C DGN
let dgn = (frame.canid >> 8) & 0x3FFFF;

// Thermostat STATUS DGN only
if (dgn !== 0x1FFE2) return null;

// Optional instance filter
let instFilter = env.get("INSTANCE");
let instance = frame.data[0];

if (instFilter !== undefined && instFilter !== null && instance !== instFilter)
    return null;

// ----------------------------
// Cool setpoint — bytes 5–6 LE
// ----------------------------
let raw = frame.data[5] | (frame.data[6] << 8);

// 0xFFFF = not available
if (raw === 0xFFFF) return null;

// RV-C scaling: 0.03125°C per bit, offset −273°C
let c = (raw * 0.03125) - 273;
let f = (c * 9/5) + 32;

// Round to whole °F
msg.payload = Math.round(f);

return msg;

// RV-C Thermostat Cool Setpoint Sender (partial update)
// DGN: 0x1FEF9
// Input: temperature in °F
//
// Adjustments:
//   • Add adjustable Celsius offset (default +0.4°C)
//   • Keep 5 decimal places in °C before RV-C conversion
//
// Only sets:
//   Bytes 5–6 = Cool Setpoint (uint16 LE)
// All other fields = 0xFF (no change)

const DGN        = 0x1FEF9;
const INSTANCE   = env.get("INSTANCE") ?? 0;
const DEST_ADDR  = 0x01;

// ---- calibration offset in Celsius ----
const C_OFFSET = 0.2;   // << adjust here

function buildFrame(dgn, da, data) {
  return {
    canid: (dgn << 8) | (da & 0xFF),
    ext: true,
    rtr: false,
    dlc: data.length,
    data
  };
}

// Normalize input to number (°F)
function toNumber(v) {
  if (v && typeof v === "object" && "value" in v) v = v.value;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

let f = toNumber(msg.payload);
if (f === null) return null;

// ---- Convert °F → °C ----
let c = (f - 32) * 5 / 9;

// ---- apply adjustable offset ----
c += C_OFFSET;

// ---- keep 5 decimal places ----
c = Number(c.toFixed(5));

// ---- Convert °C → raw RV-C units ----
// RV-C: raw = (C + 273) / 0.03125
let raw = (c + 273) / 0.03125;

// Raw must be integer
raw = Math.round(raw);

// Clamp to uint16
raw = Math.max(0, Math.min(0xFFFF, raw));

// Little-endian bytes
const lo = raw & 0xFF;
const hi = (raw >> 8) & 0xFF;

// Build data payload (only cool setpoint touched)
const data = [
  INSTANCE & 0xFF,
  0xFF,
  0xFF,
  0xFF, 0xFF,
  lo, hi
];

const frame = buildFrame(DGN, DEST_ADDR, data);

return { payload: frame };

// RV-C Thermostat STATUS decoder -> simple HVAC fan state
// DGN: 0x1FFE2
// Uses table fields:
//   Byte0: Instance
//   Byte1: bits0-3 Operating mode, bits4-5 Fan mode
//   Byte2: Fan speed (uint8)
//
// Output payload (string): "off" | "auto" | "low" | "high"

let frame = msg.payload;
if (!frame || frame.canid === undefined || !frame.data) return null;

// Extract RV-C DGN
let dgn = (frame.canid >> 8) & 0x3FFFF;

// Thermostat STATUS DGN only
if (dgn !== 0x1FFE2) return null;

// Optional instance filter
let instFilter = env.get("INSTANCE");
let instance = frame.data[0];
if (instFilter !== undefined && instFilter !== null && instance !== instFilter) return null;

// Byte1 bitfields
let b1 = frame.data[1];
let operatingMode = b1 & 0x0F;        // bits 0–3
let fanMode       = (b1 >> 4) & 0x03; // bits 4–5

// Fan speed
let fanSpeed = frame.data[2];

// Mapping rules requested
if (operatingMode === 0 && fanMode === 0) {
  msg.payload = "Off";
  return msg;
}

if (operatingMode === 1 && fanMode === 0) {
  msg.payload = "Auto";
  return msg;
}

if (operatingMode === 1 && fanMode === 1 && fanSpeed === 100) {
  msg.payload = "Low";
  return msg;
}

if (operatingMode === 1 && fanMode === 1 && fanSpeed === 200) {
  msg.payload = "High";
  return msg;
}

// Anything else: ignore
return null;

// RV-C Thermostat Fan Control Sender
// DGN: 0x1FEF9
// Instance: 0
//
// Input payload:
//   "auto"  -> fanMode = 0
//   "low"   -> fanMode = 1, fanSpeed = 100
//   "high"  -> fanMode = 1, fanSpeed = 200
//
// Only modifies:
//   Byte1 bits 4–5 (fan mode)
//   Byte2 (fan speed)
// All other bytes = 0xFF (no change)

const DGN        = 0x1FEF9;
const INSTANCE   = 0;
const DEST_ADDR  = 0x01;

function buildFrame(dgn, da, data) {
  return {
    canid: (dgn << 8) | (da & 0xFF),
    ext: true,
    rtr: false,
    dlc: data.length,
    data
  };
}

// Normalize input string
let mode = msg.payload;
if (typeof mode === "object" && mode && "value" in mode) mode = mode.value;
if (typeof mode !== "string") return null;

mode = mode.trim().toLowerCase();

// Defaults = no change
let fanModeNibble = 0xF0;   // upper bits "no change"
let fanSpeed = 0xFF;

if (mode === "Auto") {
  // fan mode = 0
  fanModeNibble = (0 << 4) | 0x0F;
  fanSpeed = 0xFF;
}
else if (mode === "Low") {
  fanModeNibble = (1 << 4) | 0x0F;
  fanSpeed = 100;
}
else if (mode === "High") {
  fanModeNibble = (1 << 4) | 0x0F;
  fanSpeed = 200;
}
else {
  return null;
}

// Build data payload
const data = [
  INSTANCE,
  fanModeNibble,
  fanSpeed,
  0xFF, 0xFF,
  0xFF, 0xFF
];

const frame = buildFrame(DGN, DEST_ADDR, data);

return { payload: frame };
